#usda 1.0

def "Scene"
{
    def Xform "Character"
    {
        custom float3[] xformOp:translate
        float3[] xformOp:translate.timeSamples = {
            1: [(0, 0, 0)],
            24: [(5, 0, 0)],
        }
    }
}

#usda 1.0

def "Scene"
{
    def "Character"
    {
        def Mesh "Body" (
            prepend apiSchemas = ["MaterialBindingAPI"]
        )
        {
            rel material:binding = </Scene/Looks/HeroMat>
        }
    }

    def "Looks"
    {
        def Material "HeroMat"
        {
            def Shader "PreviewSurface"
            {
                uniform token info:id = "UsdPreviewSurface"
                color3f inputs:diffuseColor = (0.9, 0.1, 0.1)
            }
        }
    }
}
